mapper.select:
SELECT ITEM_CD as itemCd, STOCK_QTY as stockQty 
FROM TB_ITEM 
WHERE ITEM_CD = #{itemCd}

SELECT IFNULL(STOCK_QTY, 0) 
FROM TB_ITEM 
WHERE ITEM_CD = #{itemCd}

mapper.insert:
INSERT INTO TB_ITEM_LOG (
ITEM_CD, INOUT_TYPE, QTY, BEFORE_QTY, AFTER_QTY, REF_NO, EMP_ID, REG_DT
) VALUES (
#{itemCd}, #{inoutType}, #{qty}, #{beforeQty}, #{afterQty}, #{refNo}, #{empId}, NOW()
)

mapper.update:
UPDATE TB_ITEM 
SET STOCK_QTY = STOCK_QTY + #{qty} 
WHERE ITEM_CD = #{itemCd}

UPDATE TB_ORDER 
SET STATUS = #{status}
WHERE ORDER_NO = #{orderNo}
